var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"어때, 내 선물은 마음에 드셨나?","JPN":"いかがですか？　私のプレゼントは？","ENG":"Say, do you like my present?","TWN":"怎麼樣，喜歡我的禮物嗎？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LOOP"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"선물?","JPN":"プレゼント？","ENG":"What present?","TWN":"禮物？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"설마 이 침식체들을 말하는 거야?","JPN":"まさか、この侵食体のこと？","ENG":"Are you talking about these C.O.?","TWN":"妳是說這些侵蝕體？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"바로 그렇다.","JPN":"そうです。","ENG":"That's right.","TWN":"正是如此。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"단순하고 어리석은 너희들은 솔로카오가 그저 평범한 열매인 줄 알았겠지만......","JPN":"単純で愚かなあなた方は、ソロカオをただの実だと思ったのでしょう……","ENG":"Being as simpleminded and foolish as you are, you probably thought the Solocao was a simple fruit.","TWN":"你們這些單純愚蠢的人類，大概認為獨株可可只是普通的果實，但是……"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"어...... 솔직히 한 번도 평범한 열매라고 생각해 본 적은 없는데......","JPN":"いや……正直なところ、一度もそう思ったことはない……","ENG":"Erm, actually, I've never thought of it as a normal fruit...","TWN":"呃……說實話我一次都不覺得這是普通的果實……"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"놀랍게도 솔로카오의 진실은!","JPN":"しかし、ソロカオは！","ENG":"Don't be surprised. The Solocao is","TWN":"驚人的是！獨株可可實際上！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이면세계에 떠도는 외로움과 좌절감이 열매 형태로 결정화된 것!","JPN":"裏世界に漂う寂しさと挫折が、実の形の結晶になったものです！","ENG":"actually the loneliness and despair in the Counterside, crystallized in fruit form!","TWN":"是漂盪在異界中的孤獨與挫折感，所形成的果實形態結晶！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다시 말해 언제든 각성할 수 있는 침식체의 유정란이나 마찬가지인 것이다!","JPN":"つまり、いつでも覚醒できる侵食体の卵も同然！","ENG":"In other words, it's a fertile C.O. egg that's ready to hatch anytime!","TWN":"換句話說，就相當於孵化覺醒侵蝕體的卵！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그것을 초콜릿 형태로 가공한 다음 이 바닐라 더스트 퀸의 정수를 더하면......","JPN":"それをチョコレートとして加工した後、このバニラダストクイーンのエッセンスを加えると……","ENG":"Turn it into chocolate and add this Vanilla Dust Queen extract, and...","TWN":"把它加工成巧克力後，再加入這香草皇后的精華……"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"거짓된 상업주의 뒤에 숨어서 고독을 피하려는 위선자들에게 철퇴를 가할, 제 3종 유니크 침식체!","JPN":"子供だましな商業主義の裏に隠れて、\\n孤独から逃れようとする偽善者どもに鉄槌を下す、第3種のユニーク侵食体！","ENG":"It becomes the Category 3 Unique C.O., to punish hypocrites who try to hide from their loneliness behind the false sense of security provided by commercialism,","TWN":"就可以給那些躲在虛偽商業主義背後，試圖躲避孤獨的偽善者迎頭痛擊，生成獨特的3級侵蝕體！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"론리 더 레이지 킹으로 다시 탄생하게 되는 것이다!","JPN":"ローン・リー・ザ・レイジキングへと生まれ変わるのです！","ENG":"Lone Lee the Rage King!","TWN":"它們將重新誕生為憤怒之王·隆利！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"아니, 무슨 상업주의 타령이야?","JPN":"何でここで商業主義が出てくるの？","ENG":"What commercialism?","TWN":"不是，什麼商業主義啊？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"이건 시민들에게 그냥 나눠 주는 거잖아?","JPN":"これは市民に配るものでしょ？","ENG":"We've been just giving this out to citizens.","TWN":"這不是分給市民們的東西嗎？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"그것도 공짜로!!","JPN":"しかもタダで！！","ENG":"For free!","TWN":"還是免費分給他們的！！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"조잘조잘 시끄럽다, 이 자본주의의 하수인 같으니라고!","JPN":"つべこべ言うな、この商業主義の手下め！","ENG":"Silence, you yammering puppet of capitalism!","TWN":"囉囉嗦嗦的吵死了，你這資本主義的走狗！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"발렌타인이라는 악마가 내 청춘에 남기고 간 상처는, 그런 말장난 따위로 치유할 수 없어!","JPN":"バレンタインという悪魔が私の青春に残した傷跡は、\\nそんな言葉遊びなんかじゃ癒せない！","ENG":"No matter what you say, it'll never heal the wound that this demonic Valentine's Day left in me during my youth!","TWN":"情人節這個惡魔在我青春中留下的傷痛，不是這種玩笑話能治癒的！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 일어나라! 론리 더 레이지 킹이여!","JPN":"さあ、目覚めろ！　ローン・リー・ザ・レイジキング！","ENG":"Now, rise, Lone Lee the Rage King!","TWN":"來吧，站起來吧！憤怒之王·隆利！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"일어나서 상업주의에 찌들어 있는 이 세상의 모든 초콜릿들을 짓밟아 버리도록!!","JPN":"商業主義に侵された、この世のチョコレートすべてを踏みにじりなさい！","ENG":"Rise and trample on all the chocolate in the world that's been tainted by commercialism!","TWN":"站起來踐踏著滿是商業主義的世界！踐踏這世上所有的巧克力！！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_GRAVE_DAMAGE_DOWN"},{"id":"L22_1","type":"dialog","speaker":"HARIM_REBBIT_VAL_NULL","text":{"KOREA":"와! 저거 봐, 소림아!","JPN":"わあ！　あれ見て、ミズキ！","ENG":"Whoa! Look at that, Sorim!","TWN":"哇！蕭林，看那個！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_VAL_NULL","text":{"KOREA":"초콜릿들이 저절로 움직여서 뭉치고 있어! 신기하다!","JPN":"チョコレートが自分で動いて、一つの塊になっている！　不思議だね！","ENG":"The chocolate is moving and clumping itself up! It's so amazing!","TWN":"巧克力自己動起來聚集到一起了！好神奇喔！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SORIM_REBBIT_VAL_NULL","text":{"KOREA":"비, 비상사태다, 대장! 맛있는 보급품들이 탈영하고 있어! 막아야 한다!","JPN":"ひ、非常事態だ、隊長！\\nおいしい補給品が脱走している！　止めるべきだ！","ENG":"Th-this is an emergency, Captain! Our delicious supplies are about to go AWOL! We must stop them!","TWN":"緊、緊急事態，隊長！美味的補給品在逃跑！得阻止它們才行！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_VAL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_VAL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"......확실히 비상사태이긴 하네요.","JPN":"……確かに非常事態ですわね。","ENG":"This definitely is an emergency.","TWN":"……確實是緊急事態呢。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"웃기는 이름이긴 하지만, 제 3종으로 분류되는 침식체라면 웃을 수만은 없겠죠.","JPN":"おかしな名前ですが、第3種に分類される侵食体は、冗談では済まされませんから。","ENG":"Despite its ridiculous name, it can't be trifled with if it really is Category 3,","TWN":"雖然它的名字挺好笑的，但那是被分入3級侵蝕體的傢伙啊，這可讓人笑不出來。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_VAL_NULL","text":{"KOREA":"그래서, 코핀 컴퍼니 여러분은 어떻게 하시겠어요?","JPN":"それで、コフィンカンパニーの皆様は、いかがなさいますか？","ENG":"So, members of the Coffin Company, what would you like to do?","TWN":"科芬公司的各位會怎麼做呢？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"......저렇게 알아서 하나로 합쳐 준다면 귀찮은 일이 줄어든다고 볼 수도 있지.","JPN":"……勝手に一つに集まってくれれば、面倒な手間が省ける。","ENG":"It's combining of its own accord, which means one less problem for us.","TWN":"……巧克力合體成一個也能少很多麻煩事了呢。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"거기 방송하는 아가씨들! 잘 찍고 있나?","JPN":"そこの放送っ子ども！　しっかり撮ってるか？","ENG":"Hey, you streamers! Are you filming this?","TWN":"那邊正在直播的小姐們！攝影機有好好在拍攝嗎？"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_VAL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"네, 넷!","JPN":"は、はいっ！","ENG":"Y-yes!","TWN":"有，有的！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"방금 최고 시청자 수를 갱신했어요.","JPN":"先ほど、過去最高の視聴者数を突破しました。","ENG":"We've just broke our highest viewer record.","TWN":"剛才達成最高收視率了。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GAEUN_HB_VAL_NULL","text":{"KOREA":"만세.","JPN":"わーい、やったー。","ENG":"Yay.","TWN":"萬歲。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"가은아, 리액션이 너무 짜......","JPN":"ユキちゃん、もっと派手にリアクションしてよ……","ENG":"Gaeun, that was so halfhearted...","TWN":"嘉恩啊，反應太平淡了……"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GAEUN_HB_VAL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"좋아. 덕분에 이수연에게 농땡이 피웠다고 잔소리 들을 일은 없겠군.","JPN":"よし。おかげでキズナに、サボったと小言を言われなくても済みそうだ。","ENG":"Good, now I've got something to show to Sooyeon to prove my hard work.","TWN":"太棒了，不用再聽李秀妍嘮叨說我懶了。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_VAL_NULL","text":{"KOREA":"가자, 신입. 저 불량 초콜릿 괴물만 해치우면 이 귀찮은 의뢰도 끝이다.","JPN":"行くぞ、新人。\\nあの不良チョコレート怪物さえ倒せば、この面倒な依頼もおしまいだ。","ENG":"Let's go, Rookie. We'll get rid of that unhealthy chocolate monster and get this bothersome job over with.","TWN":"去吧，新人。解決了那個不良巧克力怪，這麻煩的委託就結束了。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하하! 안타깝군! 이래서 예체능계 인간들이란!","JPN":"ははは！　残念ですね！　これだから、芸術系の人間は！","ENG":"Hah hah hah! What a shame! This is why I don't trust entertainers and athletes like you.","TWN":"哈哈哈！可惜啊！所以說藝體界的人啊！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LOOP"},{"id":"L42_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"정수를 구할 수 있게 수고해 준 너희에겐 일말의 자비를 베풀 생각도 있었는데 말이지......","JPN":"エッセンスの入手を手伝ってくれたあなた方には、情けをかけるつもりでした……","ENG":"But! Since you helped me get the extract, I'm willing to show you some degree of mercy","TWN":"本來看見你們辛辛苦苦給我收集精華，還想對你們慈悲一些……"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하지만!","JPN":"しかし！","ENG":"under one condition.","TWN":"但是！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"끝까지 내 계획을 방해하려 든다면 더 이상의 관용은 없다.","JPN":"私の計画を邪魔するつもりなら、許すことはできません。","ENG":"Stop interfering with my plan. Or there will be no mercy for you.","TWN":"竟然到最後都想要妨礙我的計畫，那我也不會再對妳們手下留情了。"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사랑이라는 달콤한 환상에 빠져 그 속에 씁쓸함을 깨닫지 못하는 우매한 인간들아!","JPN":"愛という甘い幻想に酔いしれて、その苦さに気づかない愚かな人間どもよ！","ENG":"You foolish humans who can't see the bitterness of love for its superficial sweetness!","TWN":"妳們這些陷入甜蜜愛情，而無法意識到其中苦澀的愚昧人類！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"뉘우치고 또 뉘우쳐라!!","JPN":"後悔して、後悔しまくれ！！","ENG":"Repent!","TWN":"懺悔吧懺悔吧！！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하하하하하! 으하하하하하하!","JPN":"はははははは！　ぐはははははは！","ENG":"Mwa hah hah hah! Mwa hah hah hah!","TWN":"哈哈哈哈哈哈！啊哈哈哈哈哈哈！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하...... 콜록! 콜록!","JPN":"はは……ゲホ！　ゲホッ！","ENG":"Hah hah—*Cough!* *Cough!*","TWN":"哈哈……咳哢！咳哢！"},"stage":{"bg":"CITY_STREET_FESTIVAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};